package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonCodeCalculator;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoonFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ExtraSqlService.SimpelWeddebepaling;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.Indexator;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Vergoeding;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.INDEXATOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.RKM_COREHR_CONFIG_MANAGER;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SUPPLEMENTEN_KEY;

@Slf4j
@Builder
@AllArgsConstructor
public class DiplomaToeslag {

    public static final int SCHUIF_FACTOR_100 = 2;

    private static final Integer EXTENSIE_OUD_STATUUT = 99;
    private static final Integer EXTENSIE_NIEUW_STATUUT = 98;
    private static final Set<Integer> CODES_REGELMATIGE_PRESTATIES = ImmutableSet.of(542, 942);
    private static final Set<Integer> CODES_UITZONDERLIJKE_PRESTATIES = ImmutableSet.of(541);
    private static final Integer CODE_SOCIALE_GRENS_OVERSCHREDEN = 942;

    private final NlpGlobalService globalService;
    private final ConstantManager constantManager;
    private final LoonElementVerwerker loonElementVerwerker;

    public void bereken(RekenContext context, Opdracht opdracht, MoneyMap<AardKodeExtensie> carryoverMap) {
        for (Opper opper : opdracht.getOpperSlices()) {
            bereken(context, opper, carryoverMap);
        }
    }


    public void bereken(RekenContext context, Opper opper, MoneyMap<AardKodeExtensie> carryoverMap) {
        RegulManager regulManager = context.getRegulManager();
        RekenTijd rekenTijd = context.getRekenTijd();
        LoonElementManager manager = context.getLoonElementManager();
        LoonCodeManager loonCodeManager = context.getLoonCodeManager();
        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = context.getUnchecked(RKM_COREHR_CONFIG_MANAGER);
        RkmCoreHrConfiguratie rkmCoreHrConfiguratie = rkmCoreHrConfiguratieManager.getRkmCoreHrConfiguratie(opper.getOpdracht(), rekenTijd);
        LoonCodeCalculatorFactory factory = new LoonCodeCalculatorFactory(constantManager, regulManager, loonCodeManager, globalService, rkmCoreHrConfiguratie);
        PersoonsDataManager dataManager = context.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);

        List<Vergoeding> diplomaToeslagen = new ArrayList<>();
        for (Vergoeding vergoeding : opper.getVergoedingen()) {
            AardKodeExtensie aardKodeExtensie = loonCodeManager.getByVergoeding(vergoeding);
            if (aardKodeExtensie.behoortTotGroep(LooncodeGroepKeyStrings.DIPLOMA_TOESLAG_VRW_HVZ_KEY)) {
                diplomaToeslagen.add(vergoeding);
            }
        }

        DiplomaToeslagCombinatie combinatie = null;
        if (!diplomaToeslagen.isEmpty()) {
            SimpelWeddebepaling weddebepaling = dataManager.getSimpelWeddebepaling(opper.getOpdracht(), rekenTijd.beginDatum);
            combinatie = analyseerDiplomaToeslagen(opper.getOpdracht(), weddebepaling, diplomaToeslagen, regulManager);
        }

        if (combinatie == null || combinatie == DiplomaToeslagCombinatie.FOUTE_COMBINATIE) {
            return;
        }

        BigDecimal percentage = diplomaToeslagen.get(0).getBedragWerknemer().getAmount().movePointLeft(SCHUIF_FACTOR_100);

        boolean socialeGrensOverschreden = false;
        Money basisBedragUitzonderlijkePrestaties = Money.ZERO;
        Money basisBedragRegelmatigePrestaties = Money.ZERO;

        Indexator indexator = context.getUnchecked(INDEXATOR_KEY);
        BigDecimal index = indexator.bepaalIndex(opper);

        List<NlpPrestatie> supplementen = context.getDoubleKey(SUPPLEMENTEN_KEY, opper);

        for (NlpPrestatie prestatie : supplementen) {
            int code = prestatie.getCode();
            if (prestatie.getAard().equals(AardKodeExt.S_KODE_EXT.getCode()) || (CODES_REGELMATIGE_PRESTATIES.contains(code) && !combinatie
                    .heeftRegelmatig()) || (CODES_UITZONDERLIJKE_PRESTATIES.contains(code) && !combinatie.heeftUitzonderlijk())) {
                continue;
            }

            AardKodeExtensie aardKodeExtensie = loonCodeManager.getByPrestatie(prestatie);

            socialeGrensOverschreden = socialeGrensOverschreden || code == CODE_SOCIALE_GRENS_OVERSCHREDEN;

            LoonCodeCalculator calculator = factory.genereerLoonCodeCalculator(opper, aardKodeExtensie, rekenTijd, new HashSet<>(), index);
            calculator.setZonderToeslag(!combinatie.heeftOudStatuut());

            Money bedrag = calculator.berekenBedrag100Percent(prestatie.getY());
            bedrag = indexator.indexeer(bedrag, aardKodeExtensie, opper);
            bedrag = bedrag.multiply(prestatie.getX());

            if (CODES_UITZONDERLIJKE_PRESTATIES.contains(code)) {
                basisBedragUitzonderlijkePrestaties = basisBedragUitzonderlijkePrestaties.add(bedrag);
            } else {
                if (CODES_REGELMATIGE_PRESTATIES.contains(code)) {
                    basisBedragRegelmatigePrestaties = basisBedragRegelmatigePrestaties.add(bedrag);
                }
            }
        }

        GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
        if (basisBedragUitzonderlijkePrestaties.signum() > 0) {
            AardKodeExtensie looncodeUitzPrest = gewoonLoon.createDiplomaToeslagVrijwilligerHvzUitzonderlijkePrestaties(combinatie.heeftOudStatuut());
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeUitzPrest, basisBedragUitzonderlijkePrestaties.multiply(percentage), rekenTijd,
                    carryoverMap);
        }
        if (basisBedragRegelmatigePrestaties.signum() > 0) {
            AardKodeExtensie looncodeRegPrest =
                    gewoonLoon.createDiplomaToeslagVrijwilligerHvzRegelmatigePrestaties(combinatie.heeftOudStatuut(), socialeGrensOverschreden);
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeRegPrest, basisBedragRegelmatigePrestaties.multiply(percentage), rekenTijd, carryoverMap);
        }

    }

    private DiplomaToeslagCombinatie analyseerDiplomaToeslagen(
            Opdracht opdracht, SimpelWeddebepaling weddebepaling,
            List<Vergoeding> diplomaToeslagen, RegulManager regulManager) {
        BigDecimal percentage = null;
        DiplomaToeslagCombinatie combinatie;
        Integer statuut = null;
        int uitzonderlijk = 0;
        int regelmatig = 0;

        for (Vergoeding vergoeding : diplomaToeslagen) {
            int code = vergoeding.getCode();
            int extensie = vergoeding.getExtensie();
            if (CODES_UITZONDERLIJKE_PRESTATIES.contains(code)) {
                uitzonderlijk++;
            } else {
                if (CODES_REGELMATIGE_PRESTATIES.contains(code)) {
                    regelmatig++;
                }
            }

            if (statuut == null) {
                statuut = extensie;
            } else {
                if (statuut.compareTo(vergoeding.getExtensie()) != 0) {
                    log.debug("Inconsistent statuut diplomatoeslag, vergoedingen van verschillende statuten terzelfdertijd aanwezig.");
                    regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
                }
            }

            if (percentage == null) {
                percentage = vergoeding.getBedragWerknemer().getAmount();
            } else {
                if (percentage.compareTo(vergoeding.getBedragWerknemer().getAmount()) != 0) {
                    log.debug("Inconsistent percentage diplomatoeslag, vergoedingen met verschillende percentages terzelfdertijd aanwezig.");
                    regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
                }
            }
        }
        if (uitzonderlijk > 1 || regelmatig > 1 || (regelmatig > 0 && uitzonderlijk == 0)) {
            log.debug("Foute combinatie van regelmatige en niet regelmatige vergoedingen diplomatoeslag.");
            regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
        }

        if (EXTENSIE_OUD_STATUUT.equals(statuut) && uitzonderlijk == 1 && regelmatig == 1) {
            combinatie = DiplomaToeslagCombinatie.OUD_STATUUT_REGELMATIG_EN_UITZONDERLIJK;
        } else if (EXTENSIE_OUD_STATUUT.equals(statuut) && uitzonderlijk == 1 && regelmatig == 0) {
            combinatie = DiplomaToeslagCombinatie.OUD_STATUUT_ENKEL_UITZONDERLIJK;
        } else if (EXTENSIE_NIEUW_STATUUT.equals(statuut) && uitzonderlijk == 1 && regelmatig == 1) {
            combinatie = DiplomaToeslagCombinatie.NIEUW_STATUUT_REGELMATIG_EN_UITZONDERLIJK;
        } else {
            log.debug("Foute combinatie statuut en regelmatig/uitzonderlijke vergoedingen.");
            log.debug("Statuut:{}, uitzonderlijk:{}, regelmatig:{}", statuut, uitzonderlijk, regelmatig);
            regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
            combinatie = DiplomaToeslagCombinatie.FOUTE_COMBINATIE;
        }

        if (weddebepaling != null) {
            Integer bronBeslissing = weddebepaling.getBronBeslissing();
            Integer synchronisatie = weddebepaling.getSynchronisatie();

            boolean oudStatuut = combinatie == DiplomaToeslagCombinatie.OUD_STATUUT_REGELMATIG_EN_UITZONDERLIJK
                    || combinatie == DiplomaToeslagCombinatie.OUD_STATUUT_ENKEL_UITZONDERLIJK;
            boolean nieuwStatuut = combinatie == DiplomaToeslagCombinatie.NIEUW_STATUUT_REGELMATIG_EN_UITZONDERLIJK;

            if (nieuwStatuut && !(bronBeslissing == 1 && synchronisatie == 1) && !(synchronisatie == 2 && bronBeslissing == 3)) {
                log.debug("Foute combinatie statuut en bronBeslissing/synchronisatie.");
                log.debug("Statuut:{}, bronBeslissing:{}, synchronisatie:{}", statuut, bronBeslissing, synchronisatie);
                regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
            } else if (oudStatuut && !(bronBeslissing == 2 && synchronisatie == 2)) {
                log.debug("Foute combinatie statuut en bronBeslissing/synchronisatie.");
                log.debug("Statuut:{}, bronBeslissing:{}, synchronisatie:{}", statuut, bronBeslissing, synchronisatie);
                regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
            } else {
                if (oudStatuut && opdracht.getHoedanigheid() == Hoedanigheid.DIENST_100_2015_MET_CUMUL_VRIJWILLIGE_BRANDWEER) {
                    log.debug("Foute combinatie statuut en hoedanigheid.");
                    log.debug("Statuut:{}, hoedanigheid:{}", statuut, opdracht.getHoedanigheid());
                    regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
                }
            }
        } else {
            log.debug("Geen Weddebepaling gevonden.");
            regulManager.doRegulException(opdracht, Regulkode.FOUTE_INPUT_DIPLOMATOESLAG_HVZ);
        }

        return combinatie;
    }
}
